artisan/mods.scss:
// ARTISAN STYLES

// VARIABLES
// general
$logo-width: get-width(stencilString('logo_size'));
$content-maxWidth: 1230px; // includes padding. make 'none' for full width
$productGrid-imageHeight: calc(1% * #{stencilNumber("card-image-ratio", "")});
$subcategoryGrid-imageHeight: calc(1% * #{stencilNumber("subcategory-image-ratio", "")});
$logo_fontSize: stencilNumber("logo_fontSize");
$logo_fontSize_mobile: stencilNumber("logo_fontSize_mobile");

// colours
$button--primary-backgroundColor: stencilColor("button--primary-backgroundColor");
$button--primary-backgroundColor-hover: stencilColor("button--primary-backgroundColorHover");
$button--primary-color: stencilColor("button--primary-color");
$button--primary-color-hover: stencilColor("button--primary-colorHover");
$button--default-backgroundColor: stencilColor("button--default-backgroundColor");
$button--default-backgroundColor-hover: stencilColor("button--default-backgroundColorHover");
$button--default-text: stencilColor("button--default-color");
$button--default-text-hover: stencilColor("button--default-colorHover");

$promo-backgroundColor: stencilColor("promoBar-backgroundColor");
$promo-textColor: stencilColor("promoBar-textColor");
$navUser-subMenu-background: stencilColor("navUser-dropdown-backgroundColor");
$nav-backgroundColor: stencilColor("navPages-backgroundColor");
$nav-linkColor: stencilColor("navPages-color");
$nav-linkHover: stencilColor("navPages-color-hover");
$nav-linkUnderlineColor: stencilColor("navPages-link-underline");
$nav-subMenu-background: stencilColor("navPages-subMenu-backgroundColor");
$nav-subMenu-backgroundHover: stencilColor("navPages-subMenu-backgroundColorHover");
$navCart-icon-mobile: stencilColor("navUser-cart-icon-mobile");
$nav-toggle-mobile: stencilColor("nav-toggle-mobile");
$cart-count-bg-mobile: stencilColor("navUser-indicator-backgroundColor-mobile");
$navPage-borderColor: stencilColor("navPages-subMenu-separatorColor");

$search-bg: stencilColor("search-background");
$quickSearch-backgroundColor: stencilColor("dropdown--quickSearch-backgroundColor");
$search-boxColor: stencilColor("search-box");
$search-textColor: stencilColor("search-text");

$general-linkColor: stencilColor("color-textLink");
$general-linkColorHover: stencilColor("color-textLink--hover");
$baseText-color: stencilColor("color-textBase");
$header-footer-separator-line-color: stencilColor("header-footer-separator-line-color");

$card-titleColor: stencilColor("card-title-color");
$card-image-border: stencilColor("card-image-border");

$alerts--backgroundColor: stencilColor("alerts--backgroundColor");
$alerts--textColor: stencilColor("alerts--textColor");
$alerts--linkColor: stencilColor("alerts--linkColor");

$footer-headingColor: stencilColor("footer-heading-fontColor");
$footer-textColor: stencilColor("footer-textColor");
$footer-linkColor: stencilColor("footer-linkColor");
$footer-linkColorHover: stencilColor("footer-linkColor-hover");

$carousel-textColor: stencilColor("carousel-description-color");
$carousel-textBackground: stencilColor("carousel-bgColor");
$carousel-textBackgroundOpacity: stencilNumber("carousel-textBgOpacity", "");
$carousel-ArrowBackground: stencilColor("carousel-arrow-bgColor");
$carousel-ArrowBackgroundOpacity: stencilNumber("carousel-arrow-bgOpacity", "");
$carousel-button-color: stencilColor("carousel-button-color");
$carousel-button-border-color: stencilColor("carousel-button-border-color");

$carousel-mobile-headingColor: stencilColor("carousel-mobile-title-color");
$carousel-mobile-textColor: stencilColor("carousel-mobile-description-color");
$carousel-mobile-textBackground: stencilColor("carousel-mobile-bgColor");
$carousel-mobile-button-textColor: stencilColor("carousel-mobile-button-color");
$carousel-mobile-button-border: stencilColor("carousel-mobile-button-border-color");

// ICONS
$social-media-icons--footer: stencilColor("social-media-icons-footer");
$social-media-icons--footerHover: stencilColor("social-media-icons-footer--hover");
$payment-icons-footer: stencilColor("payment-icons-footer");

// BADGES
$stockBadge-bgColor: stencilColor("stockBadge-bgColor");
$stockBadge-textColor: stencilColor("stockBadge-textColor");

$red: #F54A3A;

// GRID
$numProds--grid-desktop: calc(100% / #{stencilNumber("prods-per-row--desktop", "")});
$numProds--grid-desktop-leftCol: calc(100% / #{stencilNumber("prods-per-row--desktop--leftCol", "")});
$numProds--grid-tablet: calc(100% / #{stencilNumber("prods-per-row--tablet", "")});
$numProds--grid-mobile: calc(100% / #{stencilNumber("prods-per-row--mobile", "")});

// PRODUCT PAGE
$pdp-image-width: get-width(stencilString('product_size'));

// FONTS
$headings-font: stencilFontFamily("headings-font");
$headings-font-weight: stencilFontWeight("headings-font");
$page-headings-font: stencilFontFamily("page-headings-font");
$page-headings-font-weight: stencilFontWeight("page-headings-font");
$body-font: stencilFontFamily("body-font");
$buttons-font: stencilFontFamily("buttons-font");
$buttons-font-weight: stencilFontWeight("buttons-font");
$navPages-font: stencilFontFamily("navPages-font");
$navPages-font-weight: stencilFontWeight("navPages-font");
$cardTitle-font: stencilFontFamily("card-title-font");
$cardTitle-font-weight: stencilFontWeight("card-title-font");
$footer-headings-font: stencilFontFamily("footer-headings-font");
$footer-headings-font-weight: stencilFontWeight("footer-headings-font");

// MISC
$navPages-grow: stencilNumber("navPages-grow", "");
$subtleGrey: #f5f5f5;

[class^="icon-"]:before {
    font-family: FontAwesome;
    font-weight: normal;
    font-style: normal;
    display: inline-block;
    text-decoration: inherit;
}

.icon-check:before{content: "\f046";}
.icon-tablet:before{content: "\f10a";}
.icon-wrench:before{content: "\f0ad";}


// GENERAL
[data-content-region]{clear: both;}

h1, h2, h3, h4, h5, h6{letter-spacing: normal;}

h3, h4, h5, h6{
    font-family: $body-font;
}

.account-page h1.page-heading,
.page-heading,
.main-heading{
    color: stencilColor("color-textHeading");
    font-family: $headings-font;
    font-weight: $headings-font-weight;
}

.account-page h1.page-heading{text-align: center;}

h1.page-heading,
h1.main-heading{
    font-family: $page-headings-font;
    font-weight: $page-headings-font-weight;
    text-align: left;
}

.account-page h1.page-heading,
h2.page-heading{
    margin-top: 40px;
    margin-bottom: 40px;
    font-size: stencilNumber("fontSize-h2", "px");
}

.account-page h1.page-heading:after,
h2.page-heading:after{
    content: "";
    width: 35px;
    height: 3px;
    background: stencilColor("color-textHeading-underline");
    display: block;
    margin: auto;
}

.account .forgot-password-form{
    margin: 1rem auto;
    max-width: 500px;
    .form-prefixPostfix {
        flex-direction: column;
        gap: 1rem;

        .form-prefixPostfix-button--postfix{
            margin: 0;
        }
        .g-recaptcha{
            display: flex;
            justify-content: center;
            & + br{
                display: none;
            }
        }
    }
}

.uppercase{text-transform: uppercase;}
.center{text-align: center;}
a{text-decoration: none;}

.breadcrumbs{display: block;}

.breadcrumbs{text-align: left;}

.button{
    text-transform: stencilString('buttons-case');
}
.button:not(.dropdown-button){
    font-family: $buttons-font;
    font-weight: $buttons-font-weight;
    border-radius: 2px;
    border-width: 1px;
    border-style: solid;
}

.button:not(.button--primary):not(.optimizedCheckout-buttonPrimary):not(.heroCarousel-action){
    background: $button--default-backgroundColor;
    border-color: stencilColor("button--default-borderColor");
    color: $button--default-text;
}

.button:not(.button--primary):not(.optimizedCheckout-buttonPrimary):not(.heroCarousel-action):hover,
.card-figcaption .button:not(.button--primary):hover{
    background: $button--default-backgroundColor-hover;
    border-color: stencilColor("button--default-borderColorHover");
    color: $button--default-text-hover;
}

.button.button--primary{
    background: $button--primary-backgroundColor;
    border-color: stencilColor("button--primary-borderColor");
    color: $button--primary-color;
}

.button.button--primary:hover{
    background: $button--primary-backgroundColor-hover;
    border-color: stencilColor("button--primary-borderColorHover");
    color: $button--primary-color-hover;
}


.button:not(.button--icon) i{
    max-height: 1rem;
    max-width: 1rem;
}

.swal2-modal .swal2-cancel,
.swal2-modal .swal2-cancel:active,
.swal2-modal .swal2-cancel:focus,
.swal2-modal .swal2-cancel:hover{
    background: $button--default-backgroundColor;
    color: $button--default-text;
}

.page{margin: 0;}

.uppercase{text-transform: uppercase;}

.button.dropdown-menu-button svg{
    fill: $button--default-text;
}

.socialLinks .icon svg{fill: $general-linkColor;}
.socialLinks .icon:hover svg{fill: $general-linkColorHover;}

.navList-section:after,
.navList-section:before,
.navList:after,
.navList:before{display: none;}

// slick slider
.slick-prev,
.slick-next{
    top: 50%;
    transform: translateY(-50%);
    margin: 0;
    width: auto;
    height: auto;
}

.slick-prev:before,
.slick-next:before{
    height: 20px;
    width: 15px;
    background-size: 100% auto;
}

.slick-disabled{opacity: .3;}

// alerts
.alertBox--info{
    background-color: $alerts--backgroundColor;
    color: $alerts--textColor; 
}

.alertBox--info a{color: $alerts--linkColor;}

.container,
.banner:not(.home-banner--jewelry),
.previewCartAction,
.previewCartItem,
.heroCarousel--limited{
    max-width: $content-maxWidth;
    padding: 0 15px;
    width: 100%;
    min-width: 0;
}

.banner.home-banner--jewelry{
    max-width: 100%;
}

.container{
    clear: both;
    float: none;
}

.grid-bg{
    background: stencilColor("grid-background");
    overflow: hidden;
}

.navUser{
    max-width: $content-maxWidth;
    width: 100%;
    font-size: 1rem;
}

.navPages{
    max-width: calc($content-maxWidth - 30px);
    width: 100%;
}

.navUser,
.navPages,
.heroCarousel{
    margin: 0 auto;
}

// SOCIAL LINKS
footer .socialLinks{
    display: flex;
    flex-flow: row wrap;
}
.socialLinks .socialLinks-item{margin: 0 14px 14px 0;}

// PRODUCT GRID
.brandGrid:after,
.brandGrid:before,
.productGrid:before,
.productGrid:after,
.productView:after,
.productView:before{display: none;}

.productGrid,
.brandGrid{
    display: flex;
    flex-flow: row wrap;
}
.productGrid .product,
.brandGrid .brand{
    flex: 0 1 #{$numProds--grid-desktop};
    margin-bottom: 20px;
    max-width: #{$numProds--grid-desktop};
    overflow: visible;
}

.productGrid .card,
.brandGrid .card,
.productCarousel-slide .card,
.card{
    display: flex;
    flex-flow: column nowrap;
    margin-bottom: 0;
    height: 100%;
}
.card:not(.compareTable-card):not(.card-quick-result) .card-figure{
    border: 1px solid $card-image-border;
    display: flex;
    flex: 0 1 auto;
    flex-flow: column nowrap;
    padding-bottom: $productGrid-imageHeight;
    justify-content: center;
}

.card:not(.compareTable-card):not(.card-quick-result) .card-figure > a{
    position: absolute;
    width: 100%;
    height: 100%;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
}

.card-alt-image + .card-alt-image{display: none !important;}

.card-alt-img--hover .card-alt-image{opacity: 0;}
.card-alt-img--hover .card-main-image{opacity: 1;}

.card-alt-img--hover .card-alt-image,
.card-alt-img--hover .card-main-image{
  transition: all .5s ease-in-out;
}

.card-figure:hover .card-alt-img--hover .card-alt-image{opacity: 1;}
.card-figure:hover .card-alt-img--hover .card-main-image{opacity: 0;}

.card-figure:hover .card-figcaption{
    height: auto;
    max-height: 300px;
    padding: 15px;
    z-index: 5;
}

.card-figcaption{
    background: rgba(255,255,255,.8);
    border-top: 0;
    bottom: 0;
    height: auto;
    top: auto;
    opacity: 1;
    height: 0;
    overflow: hidden;
    max-height: 0;
    transition: max-height .5s linear;
    width: 100%;
    left: 0;
}
.card-figcaption .button{font-size: 13px;}

.card-figcaption-body{
    color: $general-linkColor;
    transform: none;
    width: 100%;
    text-align: left;
}

.button:not(.button--primary) svg{
    fill: $button--default-text;
}

.quickView .productView-images,
.quickView .productView-details{
    max-width: 50%;
    flex: 0 1 50%;
}

.card-figcaption--action-buttons{
    display: flex;
    flex-flow: row nowrap;
    justify-content: space-between;
    align-items: center;
}
.card-figcaption--action-buttons .button{
    flex: 1 1 50%;
    margin: 0;
    line-height: normal;
    padding: 12px 15px;
}

.card-figcaption--action-buttons .quickview{margin-right: 10px;}
.card .card-body{
    display: flex;
    flex: 1 1 100%;
    flex-flow: column nowrap;
    text-align: left;
}
.card-body > div{
    display: flex;
    flex-flow: column nowrap;
    width: 100%;
}

.card-body > div:not(.card-details){
    flex: 1 1 auto;
}
.card .card-title{
    align-self: flex-start;
    flex: 0 1 100%;
    font-family: $cardTitle-font;
    font-weight: $cardTitle-font-weight;
    font-size: 15px;
    letter-spacing: normal;
    margin: 0;
    text-align: left;
    text-transform: stencilString('category_name_capitalization');
}

.card-title + .card-text{
    margin-top: auto;
}

.card .card-text{
    color: $card-titleColor;
    display: flex;
    flex-flow: row wrap;
    align-items: flex-end;
    flex: 0 1 auto;
}

.card .price-section{
    display: flex;
    flex-flow: row wrap;
}
.card .price-section .price{order: 1; margin-right: 10px;}
.card .price-section .regular-price{order: 2;}
.card .price-section .price--rrp{order: 3; flex: 1 1 100%;}

.card .brand-name{
    color: $baseText-color;
    margin-bottom: 0;
}

.card .card-details{
    flex: 0 1 auto;
    align-self: flex-end;
    height: auto;
}

.regular-price{text-decoration: line-through;}

.price--discounted + .price,
.price--rrp + .price,
.regular-price + .price{
    color: $red;
    font-weight: 600;
}

.price--discounted, .price--rrp{
    color: $baseText-color;
    display: block;
    font-size: 12px;
}
.price--rrp:before{content: "MSRP ";}

.rating--small .icon,
.productView-rating .icon{
    width: 12px;
    height: 12px;
}

.rating--small .icon svg,
.productView-rating .icon svg{
    stroke: stencilColor('icon-ratingFull');
}

.card .button{
    padding: 8px 15px;
}
.card-compare{
    display: block;
    display: flex;
    align-items: center;
}

.card-compare-wrap{
    display: flex;
    align-items: center;
    font-size: 12px;
    margin-top: 5px;
}

.card-compare input{margin-right: 5px;}

.compare-button-wrap{
    display: none;
}
.compare-button-wrap .countPill{
    background: none;
    color: $general-linkColor;
    display: inline;
    margin: 0;
    height: auto;
    line-height: normal;
}
.compare-button-wrap a:hover .countPill,
.compare-button-wrap a:focus .countPill{color: $general-linkColorHover;}

// PRODUCT CAROUSEL
.productCarousel{
    width: calc(#{$content-maxWidth} + 110px);
    max-width: 100%;
    min-width: 0;
    margin: auto;
    padding: 0 60px;
}

.productCarousel .slick-track{display: flex;}

.productCarousel .slick-prev{left: 0;}
.productCarousel .slick-next{right: 0;}

// CARD BADGE
.sale-flag-side,
.stock-badge{
    font-family: $buttons-font;
    font-weight: $buttons-font-weight;
    top: -1px;
    text-align: center;
    line-height: normal;
    padding: 4px 13px;
}

// SALE BADGE
.sale-text{
    text-transform: uppercase;
}

.sale-flag-side{
    border-radius: 0;
    height: auto;
    left: -1px;
    font-size: 1rem;
}

// STOCK BADGE
.stock-badge{
    background: $stockBadge-bgColor;
    color: $stockBadge-textColor;
    right: -1px;
    position: absolute;
    text-transform: uppercase;
    z-index: 1;
}

// HEADER
header.header{z-index: 110;}
.promo-bar{
    background-color: $promo-backgroundColor;
    color: $promo-textColor;
    padding-top: 10px;
    padding-bottom: 10px;
    font-weight: 500;
    font-size: 12px;
    font-family: $navPages-font;
    font-weight: $navPages-font-weight;
    letter-spacing: 1.5px;
}
.navUser i{
    vertical-align: baseline;
}

.navUser-item-currency ul.dropdown-menu{
    border: 1px solid $navPage-borderColor;
    z-index: -1;
    margin-top: -1px;
    right: -1px;
}

.navUser-item-currency a.has-dropdown.is-open{
    border-top: 1px solid $navPage-borderColor;
    margin-top: -1px;
}
.navUser-item-currency i{
    width: 8px;
    height: 8px;
    vertical-align: middle;
}

#cart-preview-dropdown{
    width: 320px !important;
    margin-top: 10px;
}
.previewCartAction{
    border: 0;
    display: flex;
    flex-flow: row nowrap;
    padding: 15px;
    width: 100%;
}

.previewCartAction > div{
    float: left;
    flex: 1 1 auto;
}

.previewCartAction > div:not(.previewCartAction--close){
    width: 45%;
    padding: 0;
}

.previewCartAction div + div{margin-left: 10px;}

.previewCartAction--close{
    display: flex;
    width: 10%;
}
.previewCartAction .cart-preview-close{
    display: flex;
    align-items: center;
    font-size: 15px;
    line-height: normal;
    padding: 0;
}

.cart-preview-close svg{fill: $button--default-text;}
.previewCart .checkoutMultiple{
    display: block;
    padding: 0 15px 15px;
    text-align: center;
}
.cart-preview-title{
    display: inline-block;
    font-weight: 700;
    font: $body-font;
    font-size: 12px;
    padding: 14px 10px;
    text-transform: uppercase;
}
.previewCartList .previewCartItem{
    border: 0;
    display: flex;
    flex-flow: row wrap;
    align-items: center;
    padding: 0 15px;
    width: 100%;
}
.previewCart .productView-img-container{max-height: 400px;}
.previewCartItem-image{
    align-items: center;
    display: flex;
    flex: 0 1 60px;
    padding-right: 10px;
}
.previewCartItem-image img{position: static;}
.previewCartItem-content{
    display: flex;
    flex: 1 1 auto;
    flex-flow: row wrap;
    justify-content: space-between;
    padding: 0;
}
.previewCartItem-name{
    flex: 1 1 calc(100% - 65px);
    margin: 0;
}
.previewCartItem-price{
    color: $baseText-color;
    flex: 1 1 65px;
    text-align: right;
}
.cart-preview-list-item-remove{flex: 1 1 100%;}

.cart-preview-list-item-remove a{
    font-size: 11px;
    text-decoration: none;
}

.cart-preview-pricing{
    align-items: center;
    display: flex;
    flex-flow: row wrap;
    justify-content: space-between;
    padding: 10px 15px;
}
.cart-preview-total-price-label{
    text-transform: uppercase;
    font-size: 12px;
}

.cart-preview-footer{
    border-top: 1px solid stencilColor("color-greyLightest");
    margin-top: 15px;
}
.cart-preview-total-price{font-size: 15px;}
.header-logo{
    display: flex;
    flex-flow: row nowrap;
    text-align: left;
}

.header-logo h1,
.header-logo div.logo-wrap{
    flex: 0 1 calc(100% - 85px);
}
.logo-and-toggle{max-width: 100%;}
.logo-wrap a{
    max-width: 100%;
    text-overflow: ellipsis;
    line-height: 1;
}
.header-logo-text{
    white-space: normal;
    font-size: $logo_fontSize;
}
    
.header-logo h1{margin: 0;}
.header-logo h1 a,
.header-logo > a{
    padding: 0;
    width: 100%;
}

.header-logo-image{margin: 0;}

.header-logo:not(.logo-full-size) .header-logo-image{
    max-height: 100%;
    top: 50%;
    transform: translateY(-50%);
    position: relative;
}

.logo-full-size .header-logo-image{
    position: static;
}
.logo-full-size .header-logo-image-container:after{display: none;}

.navUser-item-cartLabel{display: inline;}
.navUser-item--cart .countPill{border-radius: 0;}

// QUICK SEARCH
.quickSearchWrap > div{position: relative;}
.quickSearchWrap .form-input,
.navPages-quickSearch .form-input{
    background: $search-boxColor;
    border: 1px solid $search-bg;
    border-radius: 0;
    color: $search-textColor;
    height: 45px;
    padding-left: 45px;
}
.quickSearchWrap .form-input::placeholder { /* Chrome, Firefox, Opera, Safari 10.1+ */
    color: $search-textColor;
    opacity: 1; /* Firefox */
}

.quickSearchWrap .form-input:-ms-input-placeholder { /* Internet Explorer 10-11 */
    color: $search-textColor;
}

.quickSearchWrap .form-input::-ms-input-placeholder { /* Microsoft Edge */
    color: $search-textColor;
}

.quickSearchWrap .form-button,
.navPages-quickSearch .form-button{
    height: 45px;
    padding: 0 19px;
    position: absolute;
    left: 0;
    top: 0;
}
.quickSearchWrap .form-button .icon,
.navPages-quickSearch .form-button .icon{
    width: 19px;
    height: 19px;
}
.navPages-quickSearch form{
    position: relative;
}

.quickSearchMessage{
    font-size: 15px;
    text-align: left;
    padding: 0 20px 15px;
    font-weight: $cardTitle-font-weight;
    font-family: $cardTitle-font;
    text-transform: uppercase;
    color: stencilColor("color-textHeading");
}

.quickSearchResults{
    background: $quickSearch-backgroundColor;
    border: 1px solid $search-bg;
    border-top: 0;
    width: 100%;
    max-width: 100%;
    font-size: 13px;
}

.quickSearchResults h5{
    background: #f9f9f9;
    border-top: 1px solid $search-bg;
    padding: 15px 20px;
    margin: 0;
    font-family: $cardTitle-font;
    font-weight: $cardTitle-font-weight;
}

.quickSearchResults .card-figcaption{display: none;}

.quickSearchResults .card--alternate:hover{border-color: #fff;}
.quickSearchResults .card--alternate:hover .card-body{background: none;}

.quickSearchResults .productGrid{
    display: block;
    margin: 0;
}
.quickSearchResults ul .product{
    display: block;
    margin: 0;
    max-width: none;
    padding: 0;
    width: 100%;
    position: relative;
}
.quickSearchResults li .overlay-link{
    position: absolute;
    left: 0;
    top: 0;
    height: 100%;
    width: 100%;
}
.quickSearchResults .card{
    align-items: flex-start;
    border: 0;
    border-bottom: 1px solid $subtleGrey;
    display: flex;
    flex-flow: row nowrap;
    margin-bottom: 0;
    padding: 12px 20px;
}
.quickSearchResults .card:hover{
    border-color: $quickSearch-backgroundColor;
}
.quickSearchResults .productGrid li.product .card-figure{
    border: 1px solid $subtleGrey;
    display: block;
    flex: 1 1 75px;
    height: auto;
    padding-bottom: 0;
}
.quickSearchResults .card-figure > a{
    position: static;
    transform: none;
    display: block;
}
.quickSearchResults .card-image{
    max-height: 75px;
    padding: 5px;
}

.quickSearchResults div.card-body{
    background: $quickSearch-backgroundColor;
    flex: 1 1 calc(100% - 75px);
    padding: 0 0 0 15px;
    font-size: 12px;
}
.quickSearchResults .card-title{font-size: 13px;}

.quickSearchResults .card-figcaption-button{display: none;}

.quickSearchResults .stock-message{font-size: .8rem;}

.quickSearchResults button{
    border: 1px solid $baseText-color;
    width: calc(100% - 24px);
    text-transform: uppercase;
    margin: 12px;
    font-weight: $buttons-font-weight;
    font-family: $buttons-font;
    padding: 10px;
}

