}
.footer-payment-icons .footer-payment-icon{
    width: 50px;
    height: 30px;
}
.footer-payment-icons svg.footer-payment-icon-visa{
    width: 37px;
    height: 12px;
}
.footer-payment-icons svg.footer-payment-icon-amex{
    width: 48px;
    height: 19px;
}
.footer-payment-icons svg.footer-payment-icon-paypal{
    width: 52px;
