}
.footer-payment-icons svg.footer-payment-icon-discover{
    width: 54px;
    height: 8px;
}
.footer-payment-icons svg{
    fill: $payment-icons-footer;
}

.footer-copyright{
    border-top: 1px solid $header-footer-separator-line-color;
    padding-top: 20px;
    display: flex;
    flex-flow: row wrap;
    align-items: center;
    justify-content: space-between;
}

// BANNERS
.banners{
    background-color: transparent;
    color: $baseText-color;
    padding: .78571rem 0;
}
.promo-box-row ul{
    display: flex;
    justify-content: space-between;
    list-style: none;
    margin: 0;
}
.promo-box-row ul{flex-flow: row wrap;}

.promo-box-row li{flex: 0 1 32.5%;}

.promo-box-row img{width: 100%;}

.promo-banner{
    background: #eff0f2;
    text-align: left;
    font-family: $headings-font;
    overflow: hidden;
}
.promo-banner ul{
    display: flex;
    flex-flow: row nowrap;
    justify-content: space-around;
    list-style: none;
    margin: 0;
}

.promo-banner li{
    align-items: center;
    display: flex;
    flex: 0 1 33.333%;
    flex-flow: row nowrap;
    justify-content: center;
    padding: 0 15px;
    position: relative;
    text-align: center;
}
.promo-banner li:not(:last-child):after{
    background: #fff;
    content: "";
    display: inline-block;
    height: 300px;
    position: absolute;
    right: -8px;
    top: -128px;
    width: 6px;
    -webkit-transform: rotate(15deg);
    -moz-transform: rotate(15deg);
    -ms-transform: rotate(15deg);
    transform: rotate(15deg);
}
.promo-banner em{
    color: $nav-backgroundColor;
    display: flex;
    flex: 0 1 auto;
    font-size: 48px;
}
.promo-banner li > div{
    display: inline-block;
    flex: 0 1 auto;
    text-align: left;
    vertical-align: middle;
}
.promo-banner strong{color: $button--primary-backgroundColor; font-size: 20px; font-weight: normal;}
.promo-banner span{text-align: left;}
.promo-banner strong + span{
    display: block;
    font-size: 16px;
}

// CAROUSEL
.heroCarousel:not(.heroCarousel--limited){
    width: 100%;
    max-width: 1440px;
    min-width: 0;
}
.heroCarousel a{
    text-decoration: none;
}
.heroCarousel.slick-slider{
    margin-bottom: 0;
    z-index: 0;
}

.slick-slide{height: auto;}

.heroCarousel-title{
    font-family: $headings-font;
    font-weight: $headings-font-weight;
    font-size: 32px;
}
.heroCarousel-title + .heroCarousel-description{
    margin-top: 17px;
}
.heroCarousel-action,
.heroCarousel-action:hover,
.heroCarousel-action:focus{
    background: transparent;
    border: 1px solid $carousel-button-border-color;
    color: $carousel-button-color;
}

.heroCarousel .slick-next::before,
.heroCarousel  .slick-prev::before{
    background-size: 100% auto;
    height: 20px;
    width: 15px;
}

.heroCarousel .slick-prev,
.heroCarousel .slick-next{
    opacity: 0;
    -webkit-transition: opacity .3s ease-in-out;
    transition: opacity .3s ease-in-out;
}

.slick-prev,
.slick-next,
.slick-prev:hover,
.slick-next:hover,
.slick-prev:focus,
.slick-next:focus{
    background-color: rgba($carousel-ArrowBackground, $carousel-ArrowBackgroundOpacity);
    height: auto;
    padding: 10px;
    width: auto;
}

.heroCarousel:hover .slick-prev,
.heroCarousel:hover .slick-next{
    opacity: 1;
}

.heroCarousel .slick-dots li{
    background: transparent;
    height: auto;
    width: auto;
    text-align: center;
}

.slick-dots li button,
.slick-dots li button::before{
    border-width: 2px;
    height: 10px;
    width: 10px;
}
.slick-dots li button::before{
    top: -2px;
    left: -2px;
}
.heroCarousel .slick-dots li button:before,
.heroCarousel .slick-dots li button:hover:before,
.heroCarousel .slick-dots li button:focus:before{
    opacity: 1;
}

